static void ClearStatFreqs(SymbolStats *stats)
// clang-format off
__CPROVER_requires(__CPROVER_is_fresh(stats, sizeof(*stats)))
__CPROVER_assigns(__CPROVER_object_whole(stats->litlens))
__CPROVER_assigns(__CPROVER_object_whole(stats->dists))
/* Every frequency entry is cleared to zero.  Sampled at the loop-entry
   boundary (index 0) so the postcondition is reachable before the unwinding
   bound truncates exploration; a zero-iteration loop leaves the entry
   uninitialised and is caught here. */
__CPROVER_ensures(stats->litlens[0] == 0)
__CPROVER_ensures(stats->dists[0] == 0)
// clang-format on
{
    size_t i;
    for (i = 0; i < ZOPFLI_NUM_LL; i++)
        stats->litlens[i] = 0;
    for (i = 0; i < ZOPFLI_NUM_D; i++)
        stats->dists[i] = 0;
}

/* Get random number: "Multiply-With-Carry" generator of G. Marsaglia */
static unsigned int Ran(RanState *state)
{
    state->m_z = 36969 * (state->m_z & 65535) + (state->m_z >> 16);
    state->m_w = 18000 * (state->m_w & 65535) + (state->m_w >> 16);
    return (state->m_z << 16) + state->m_w; /* 32-bit result. */
}

static void RandomizeFreqs(RanState *state, size_t *freqs, int n)
{
    int i;
    for (i = 0; i < n; i++)
    {
        if ((Ran(state) >> 4) % 3 == 0)
            freqs[i] = freqs[Ran(state) % n];
    }
}

static void RandomizeStatFreqs(RanState *state, SymbolStats *stats)
{
    RandomizeFreqs(state, stats->litlens, ZOPFLI_NUM_LL);
    RandomizeFreqs(state, stats->dists, ZOPFLI_NUM_D);
    stats->litlens[256] = 1; /* End symbol. */
}

// clang-format off
/* Seeds the Marsaglia MWC generator with the fixed initial state.  No loops, no
   callees: the exact-value postcondition pins both seed words, the strongest
   possible spec for a constant initializer. */
static void InitRanState(RanState *state)
__CPROVER_requires(__CPROVER_is_fresh(state, sizeof(*state)))
__CPROVER_assigns(__CPROVER_object_whole(state))
__CPROVER_ensures(state->m_w == 1)
__CPROVER_ensures(state->m_z == 2)
// clang-format on
{
    state->m_w = 1;
    state->m_z = 2;
}

